+/// Scan a hex float (0x[h...h][.h...h][pN]) per C11 7.21.6.2.
+/// Called after the optional sign and 0x prefix have been detected.
+fn scan_hex_float(
+    input: &[u8],
+    _start_pos: usize,
+    mut i: usize,
+    mut chars_read: usize,
+    negative: bool,
+    max_chars: usize,
